/// Look up a preset's JSON config by ID.
/// Returns None if the ID is not found.
pub fn get_preset_json(id: &str) -> Option<&'static str> {
    match id {
        "demo" => Some(PRESET_demo_JSON),
        "g2do_simple" => Some(PRESET_g2do_simple_JSON),
        "g2do_bold" => Some(PRESET_g2do_bold_JSON),
        "g2do_sweep" => Some(PRESET_g2do_sweep_JSON),
        "gpu_wgpu" => Some(PRESET_gpu_wgpu_JSON),
        "crosscoder_sim" => Some(PRESET_crosscoder_sim_JSON),
        "two_population_coupled" => Some(PRESET_two_population_coupled_JSON),
        "stimulus_patterns" => Some(PRESET_stimulus_patterns_JSON),
        "jansen_rit_evoked" => Some(PRESET_jansen_rit_evoked_JSON),
        "mpr_sweep" => Some(PRESET_mpr_sweep_JSON),
        "whole_brain_multi_model" => Some(PRESET_whole_brain_multi_model_JSON),
        "wilson_cowan_ring" => Some(PRESET_wilson_cowan_ring_JSON),
        _ => None,
    }
}
